transform_js:
const categoryData = [];
const values = [];
rawData.rows.forEach(r => {
  categoryData.push(r.date);
  // ECharts Candlestick expected order: [open, close, lowest, highest]
  values.push([r.open, r.close, r.lowest, r.highest]);
});
// 生成したダミーデータをさらに10日分ほど追加してチャートの見た目をリッチに
let lastDate = new Date('2026-03-07');
let lastClose = 45;
for(let i=1; i<=15; i++) {
   lastDate.setDate(lastDate.getDate() + 1);
   categoryData.push(lastDate.toISOString().split('T')[0]);
   const open = lastClose + (Math.random() - 0.5) * 10;
   const close = open + (Math.random() - 0.5) * 15;
   const lowest = Math.min(open, close) - Math.random() * 5;
   const highest = Math.max(open, close) + Math.random() * 5;
   values.push([open, close, lowest, highest]);
   lastClose = close;
}
transformedData = { categoryData, values };

